import{_ as e,o as i,c as s,ag as t}from"./chunks/framework.DEqXEGcv.js";const k=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/reference/faq.md","filePath":"zh/docs/reference/faq.md"}'),l={name:"zh/docs/reference/faq.md"};function o(r,a,h,d,n,c){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="安装相关" tabindex="-1">安装相关 <a class="header-anchor" href="#安装相关" aria-label="Permalink to &quot;安装相关&quot;">​</a></h2><h3 id="安装后无法访问" tabindex="-1">安装后无法访问？ <a class="header-anchor" href="#安装后无法访问" aria-label="Permalink to &quot;安装后无法访问？&quot;">​</a></h3><p>检查以下几点：</p><ol><li>RDE 服务是否正在运行：<code>sudo systemctl status rde</code></li><li>端口是否被占用：<code>sudo ss -tlnp | grep :80</code></li><li>防火墙是否放行端口：<code>sudo ufw allow 80</code></li></ol><h3 id="支持哪些操作系统" tabindex="-1">支持哪些操作系统？ <a class="header-anchor" href="#支持哪些操作系统" aria-label="Permalink to &quot;支持哪些操作系统？&quot;">​</a></h3><p>目前支持 Debian/Ubuntu 系列（提供 DEB 安装包）。其他 Linux 发行版可从源码编译安装。</p><h3 id="如何更新到最新版本" tabindex="-1">如何更新到最新版本？ <a class="header-anchor" href="#如何更新到最新版本" aria-label="Permalink to &quot;如何更新到最新版本？&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/ruizi-store/rde/releases/latest/download/rde_amd64.deb</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./rde_amd64.deb</span></span></code></pre></div><h2 id="使用相关" tabindex="-1">使用相关 <a class="header-anchor" href="#使用相关" aria-label="Permalink to &quot;使用相关&quot;">​</a></h2><h3 id="docker-应用商店看不到容器" tabindex="-1">Docker 应用商店看不到容器？ <a class="header-anchor" href="#docker-应用商店看不到容器" aria-label="Permalink to &quot;Docker 应用商店看不到容器？&quot;">​</a></h3><p>确保服务器已安装 Docker，且 RDE 运行用户有 Docker 权限：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $USER</span></span></code></pre></div><h3 id="文件上传失败" tabindex="-1">文件上传失败？ <a class="header-anchor" href="#文件上传失败" aria-label="Permalink to &quot;文件上传失败？&quot;">​</a></h3><ul><li>检查磁盘空间是否充足</li><li>大文件上传支持 TUS 断点续传，刷新页面后可恢复上传</li><li>检查反向代理是否限制了请求体大小（Nginx 需设置 <code>client_max_body_size</code>）</li></ul><h3 id="终端连接断开" tabindex="-1">终端连接断开？ <a class="header-anchor" href="#终端连接断开" aria-label="Permalink to &quot;终端连接断开？&quot;">​</a></h3><p>终端使用 WebSocket 连接，确保：</p><ol><li>反向代理正确转发 WebSocket（配置 <code>Upgrade</code> 头）</li><li>反向代理没有设置过短的超时时间</li></ol><h3 id="如何更换端口" tabindex="-1">如何更换端口？ <a class="header-anchor" href="#如何更换端口" aria-label="Permalink to &quot;如何更换端口？&quot;">​</a></h3><p>编辑 <code>/etc/rde/conf.conf</code> 修改 <code>port</code> 配置项，然后重启服务。</p><h2 id="增值服务相关" tabindex="-1">增值服务相关 <a class="header-anchor" href="#增值服务相关" aria-label="Permalink to &quot;增值服务相关&quot;">​</a></h2><h3 id="docker-镜像拉取失败" tabindex="-1">Docker 镜像拉取失败？ <a class="header-anchor" href="#docker-镜像拉取失败" aria-label="Permalink to &quot;Docker 镜像拉取失败？&quot;">​</a></h3><ol><li>检查网络连接</li><li>尝试使用镜像加速（参考 <a href="/zh/docs/guide/i18n.html">国际化与镜像加速</a>）</li></ol><h3 id="如何查看会员到期时间" tabindex="-1">如何查看会员到期时间？ <a class="header-anchor" href="#如何查看会员到期时间" aria-label="Permalink to &quot;如何查看会员到期时间？&quot;">​</a></h3><p>在 RDE 设置中查看「会员信息」，或登录 <a href="/shop.html">会员商城</a> 查看。</p><h2 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to &quot;其他问题&quot;">​</a></h2><p>有更多问题？欢迎 <a href="/community.html">加入 QQ 交流群</a> 与我们沟通。</p>`,27)])])}const u=e(l,[["render",o]]);export{k as __pageData,u as default};
